    "\n"
    "    /// Reciprocal of tau.\n"
    "    const float INV_TAU = 0.15915494309189533577;\n"
    "\n"
    "    /// Small epsilon for safe division and normalization guards.\n"
    "    const float EPSILON = 1e-6;\n"
    "\n"
    "    /// Square root of 2.\n"
    "    const float SQRT_2 = 1.41421356237309504880;\n"
    "\n"
    "    /// Reciprocal square root of 2.\n"
    "    const float INV_SQRT_2 = 0.70710678118654752440;\n"
    "\n"
    "    // ============================================\n"
    "    // Range Mapping\n"
    "    // ============================================\n"
    "\n"
    "    /// Returns the interpolation factor for value in the range [a, b].\n"
    "    inverse_lerp :: (float a, float b, float value) -> float {\n"
    "        return (value - a) / (b - a);\n"
    "    }\n"
    "\n"
    "    /// Returns the component-wise interpolation factor for value in [a, b].\n"
    "    inverse_lerp :: (float2 a, float2 b, float2 value) -> float2 {\n"
    "        return (value - a) / (b - a);\n"
    "    }\n"
    "\n"
    "    /// Returns the component-wise interpolation factor for value in [a, b].\n"
    "    inverse_lerp :: (float3 a, float3 b, float3 value) -> float3 {\n"
    "        return (value - a) / (b - a);\n"
    "    }\n"
    "\n"
    "    /// Returns the component-wise interpolation factor for value in [a, b].\n"
    "    inverse_lerp :: (float4 a, float4 b, float4 value) -> float4 {\n"
    "        return (value - a) / (b - a);\n"
    "    }\n"
    "\n"
    "    /// Returns saturate(inverse_lerp(a, b, value)).\n"
    "    inverse_lerp_clamped :: (float a, float b, float value) -> float {\n"
    "        return saturate(inverse_lerp(a, b, value));\n"
    "    }\n"
    "\n"
    "    /// Remaps a scalar from one range to another.\n"
    "    remap :: (float value, float in_min, float in_max, float out_min, float out_max) -> float {\n"
    "        float t = inverse_lerp(in_min, in_max, value);\n"
    "        return out_min + t * (out_max - out_min);\n"
    "    }\n"
    "\n"
    "    /// Remaps a vector from one range to another component-wise.\n"
    "    remap :: (float2 value, float2 in_min, float2 in_max, float2 out_min, float2 out_max) -> float2 {\n"
    "        float2 t = inverse_lerp(in_min, in_max, value);\n"
    "        return out_min + t * (out_max - out_min);\n"
    "    }\n"
    "\n"
    "    /// Remaps a vector from one range to another component-wise.\n"
    "    remap :: (float3 value, float3 in_min, float3 in_max, float3 out_min, float3 out_max) -> float3 {\n"
    "        float3 t = inverse_lerp(in_min, in_max, value);\n"
    "        return out_min + t * (out_max - out_min);\n"
    "    }\n"
    "\n"
    "    /// Remaps a vector from one range to another component-wise.\n"
    "    remap :: (float4 value, float4 in_min, float4 in_max, float4 out_min, float4 out_max) -> float4 {\n"
    "        float4 t = inverse_lerp(in_min, in_max, value);\n"
    "        return out_min + t * (out_max - out_min);\n"
    "    }\n"
    "\n"
    "    /// Remaps a scalar from one range to another, clamping the input range factor to [0, 1].\n"
    "    remap_clamped :: (float value, float in_min, float in_max, float out_min, float out_max) -> float {\n"
    "        float t = saturate(inverse_lerp(in_min, in_max, value));\n"
    "        return out_min + t * (out_max - out_min);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Safe Operations\n"
    "    // ============================================\n"
    "\n"
    "    /// Returns 1 / x, or 0 when x is too close to zero.\n"
    "    safe_rcp :: (float x) -> float {\n"
    "        if (abs(x) > EPSILON) {\n"
    "            return 1.0 / x;\n"
    "        }\n"
    "        return 0.0;\n"
    "    }\n"
    "\n"
    "    /// Returns a / b, or 0 when b is too close to zero.\n"
    "    safe_divide :: (float a, float b) -> float {\n"
    "        if (abs(b) > EPSILON) {\n"
    "            return a / b;\n"
    "        }\n"
    "        return 0.0;\n"
    "    }\n"
    "\n"
    "    /// Returns a / b, or fallback when b is too close to zero.\n"
    "    safe_divide :: (float a, float b, float fallback) -> float {\n"
    "        if (abs(b) > EPSILON) {\n"
    "            return a / b;\n"
    "        }\n"
    "        return fallback;\n"
    "    }\n"
    "\n"
    "    /// Returns component-wise a / b, using zero for near-zero denominators.\n"
    "    safe_divide :: (float2 a, float2 b) -> float2 {\n"
    "        return float2(safe_divide(a.x, b.x), safe_divide(a.y, b.y));\n"
    "    }\n"
    "\n"
    "    /// Returns component-wise a / b, using zero for near-zero denominators.\n"
    "    safe_divide :: (float3 a, float3 b) -> float3 {\n"
    "        return float3(safe_divide(a.x, b.x), safe_divide(a.y, b.y), safe_divide(a.z, b.z));\n"
    "    }\n"
    "\n"
    "    /// Returns component-wise a / b, using zero for near-zero denominators.\n"
    "    safe_divide :: (float4 a, float4 b) -> float4 {\n"
    "        return float4(safe_divide(a.x, b.x), safe_divide(a.y, b.y), safe_divide(a.z, b.z), safe_divide(a.w, b.w));\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float2, returning +X when length is too small.\n"
    "    safe_normalize :: (float2 v) -> float2 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return float2(1.0, 0.0);\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float2, returning fallback when length is too small.\n"
    "    safe_normalize_with_fallback :: (float2 v, float2 fallback) -> float2 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return fallback;\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float3, returning +Y when length is too small.\n"
    "    safe_normalize :: (float3 v) -> float3 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return float3(0.0, 1.0, 0.0);\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float3, returning fallback when length is too small.\n"
    "    safe_normalize_with_fallback :: (float3 v, float3 fallback) -> float3 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return fallback;\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float4, returning +W when length is too small.\n"
    "    safe_normalize :: (float4 v) -> float4 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return float4(0.0, 0.0, 0.0, 1.0);\n"
    "    }\n"
    "\n"
    "    /// Normalizes a float4, returning fallback when length is too small.\n"
    "    safe_normalize_with_fallback :: (float4 v, float4 fallback) -> float4 {\n"
    "        float len_sq = dot(v, v);\n"
    "        if (len_sq > EPSILON * EPSILON) {\n"
    "            return v * rsqrt(len_sq);\n"
    "        }\n"
    "        return fallback;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Vector Metrics\n"
    "    // ============================================\n"
    "\n"
    "    /// Returns dot(v, v) without taking a square root.\n"
    "    length_squared :: (float2 v) -> float {\n"
    "        return dot(v, v);\n"
    "    }\n"
    "\n"
    "    /// Returns dot(v, v) without taking a square root.\n"
    "    length_squared :: (float3 v) -> float {\n"
    "        return dot(v, v);\n"
    "    }\n"
    "\n"
    "    /// Returns dot(v, v) without taking a square root.\n"
    "    length_squared :: (float4 v) -> float {\n"
    "        return dot(v, v);\n"
    "    }\n"
    "\n"
    "    /// Returns squared distance between two points without taking a square root.\n"
    "    distance_squared :: (float2 a, float2 b) -> float {\n"
    "        return length_squared(a - b);\n"
    "    }\n"
    "\n"
    "    /// Returns squared distance between two points without taking a square root.\n"
    "    distance_squared :: (float3 a, float3 b) -> float {\n"
    "        return length_squared(a - b);\n"
    "    }\n"
    "\n"
    "    /// Returns squared distance between two points without taking a square root.\n"
    "    distance_squared :: (float4 a, float4 b) -> float {\n"
    "        return length_squared(a - b);\n"
    "    }\n"
    "\n"
    "    /// Returns max(dot(a, b), 0), common in lighting equations.\n"
    "    saturate_dot :: (float3 a, float3 b) -> float {\n"
    "        return max(dot(a, b), 0.0);\n"
    "    }\n"
    "\n"
    "    /// Returns clamp(dot(a, b), -1, 1), useful before acos.\n"
    "    clamped_dot :: (float3 a, float3 b) -> float {\n"
    "        return clamp(dot(a, b), -1.0, 1.0);\n"
    "    }\n"
    "\n"
    "    /// Returns the angle in radians between two vectors.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Dot_product\n"
    "    angle_between :: (float3 a, float3 b) -> float {\n"
    "        float3 na = safe_normalize(a);\n"
    "        float3 nb = safe_normalize(b);\n"
    "        return acos(clamped_dot(na, nb));\n"
    "    }\n"
    "\n"
    "    /// Projects vector v onto vector onto.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Vector_projection\n"
    "    project_onto :: (float3 v, float3 onto) -> float3 {\n"
    "        float denom = dot(onto, onto);\n"
    "        if (denom > EPSILON * EPSILON) {\n"
    "            return onto * (dot(v, onto) / denom);\n"
    "        }\n"
    "        return float3(0.0);\n"
    "    }\n"
    "\n"
    "    /// Rejects vector v from vector onto, returning the component perpendicular to onto.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Vector_projection\n"
    "    reject_from :: (float3 v, float3 onto) -> float3 {\n"
    "        return v - project_onto(v, onto);\n"
    "    }\n"
    "\n"
    "    /// Returns any normalized tangent perpendicular to normal.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Orthonormal_basis\n"
    "    orthonormal_tangent :: (float3 normal) -> float3 {\n"
    "        float3 n = safe_normalize(normal);\n"
    "        float3 up = abs(n.z) < 0.999 ? float3(0.0, 0.0, 1.0) : float3(1.0, 0.0, 0.0);\n"
    "        return safe_normalize(cross(up, n));\n"
    "    }\n"
    "\n"
    "    /// Returns a unit vector facing the same hemisphere as reference.\n"
    "    face_same_hemisphere :: (float3 v, float3 reference) -> float3 {\n"
    "        return dot(v, reference) < 0.0 ? -v : v;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Power Shortcuts\n"
    "    // ============================================\n"
    "\n"
    "    /// Returns x squared.\n"
    "    square :: (float x) -> float {\n"
    "        return x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x squared component-wise.\n"
    "    square :: (float2 x) -> float2 {\n"
    "        return x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x squared component-wise.\n"
    "    square :: (float3 x) -> float3 {\n"
    "        return x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x squared component-wise.\n"
    "    square :: (float4 x) -> float4 {\n"
    "        return x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x cubed.\n"
    "    cube :: (float x) -> float {\n"
    "        return x * x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x cubed component-wise.\n"
    "    cube :: (float2 x) -> float2 {\n"
    "        return x * x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x cubed component-wise.\n"
    "    cube :: (float3 x) -> float3 {\n"
    "        return x * x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x cubed component-wise.\n"
    "    cube :: (float4 x) -> float4 {\n"
    "        return x * x * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x^4.\n"
    "    pow4 :: (float x) -> float {\n"
    "        float x2 = x * x;\n"
    "        return x2 * x2;\n"
    "    }\n"
    "\n"
    "    /// Returns x^5, common in Schlick Fresnel approximations.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Schlick%27s_approximation\n"
    "    pow5 :: (float x) -> float {\n"
    "        float x2 = x * x;\n"
    "        return x2 * x2 * x;\n"
    "    }\n"
    "\n"
    "    /// Returns x^5 component-wise.\n"
    "    pow5 :: (float3 x) -> float3 {\n"
    "        float3 x2 = x * x;\n"
    "        return x2 * x2 * x;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Transformations\n"
    "    // ============================================\n"
    "\n"
    "    /// Rotates a 2D point around the origin by angle radians.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Rotation_matrix\n"
    "    rotate_2d :: (float2 p, float angle) -> float2 {\n"
    "        float c = cos(angle);\n"
    "        float s = sin(angle);\n"
    "        return float2(p.x * c - p.y * s, p.x * s + p.y * c);\n"
    "    }\n"
    "\n"
    "    /// Rotates a 3D vector around an axis using Rodrigues' rotation formula.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Rodrigues%27_rotation_formula\n"
    "    rotate_axis_angle :: (float3 v, float3 axis, float angle) -> float3 {\n"
    "        float3 a = safe_normalize(axis);\n"
    "        float c = cos(angle);\n"
    "        float s = sin(angle);\n"
    "        return v * c + cross(a, v) * s + a * dot(a, v) * (1.0 - c);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Step Functions\n"
    "    // ============================================\n"
    "\n"
    "    /// Returns a clamped linear step from edge0 to edge1.\n"
    "    linear_step :: (float edge0, float edge1, float x) -> float {\n"
    "        return saturate((x - edge0) / (edge1 - edge0));\n"
    "    }\n"
    "\n"
    "    /// Returns a clamped linear step from edge0 to edge1 component-wise.\n"
    "    linear_step :: (float2 edge0, float2 edge1, float2 x) -> float2 {\n"
    "        return saturate((x - edge0) / (edge1 - edge0));\n"
    "    }\n"
    "\n"
    "    /// Returns a clamped linear step from edge0 to edge1 component-wise.\n"
    "    linear_step :: (float3 edge0, float3 edge1, float3 x) -> float3 {\n"
    "        return saturate((x - edge0) / (edge1 - edge0));\n"
    "    }\n"
    "\n"
    "    /// Returns Perlin's quintic smootherstep with zero first and second derivatives at edges.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Smoothstep\n"
    "    smootherstep :: (float edge0, float edge1, float x) -> float {\n"
    "        float t = saturate((x - edge0) / (edge1 - edge0));\n"
    "        return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n"
    "    }\n"
    "\n"
    "    /// Returns Perlin's quintic smootherstep component-wise.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Smoothstep\n"
    "    smootherstep :: (float2 edge0, float2 edge1, float2 x) -> float2 {\n"
    "        float2 t = saturate((x - edge0) / (edge1 - edge0));\n"
    "        return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n"
    "    }\n"
    "\n"
    "    /// Returns Perlin's quintic smootherstep component-wise.\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Smoothstep\n"
    "    smootherstep :: (float3 edge0, float3 edge1, float3 x) -> float3 {\n"
    "        float3 t = saturate((x - edge0) / (edge1 - edge0));\n"
    "        return t * t * t * (t * (t * 6.0 - 15.0) + 10.0);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Easing Functions - Quadratic\n"
    "    // ============================================\n"
    "\n"
    "    /// Quadratic ease-in curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInQuad\n"
    "    ease_in_quad :: (float t) -> float {\n"
    "        return t * t;\n"
    "    }\n"
    "\n"
    "    /// Quadratic ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutQuad\n"
    "    ease_out_quad :: (float t) -> float {\n"
    "        return t * (2.0 - t);\n"
    "    }\n"
    "\n"
    "    /// Quadratic ease-in-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInOutQuad\n"
    "    ease_in_out_quad :: (float t) -> float {\n"
    "        if (t < 0.5) {\n"
    "            return 2.0 * t * t;\n"
    "        }\n"
    "        return 1.0 - 2.0 * (1.0 - t) * (1.0 - t);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Easing Functions - Cubic\n"
    "    // ============================================\n"
    "\n"
    "    /// Cubic ease-in curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInCubic\n"
    "    ease_in_cubic :: (float t) -> float {\n"
    "        return t * t * t;\n"
    "    }\n"
    "\n"
    "    /// Cubic ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutCubic\n"
    "    ease_out_cubic :: (float t) -> float {\n"
    "        float u = 1.0 - t;\n"
    "        return 1.0 - u * u * u;\n"
    "    }\n"
    "\n"
    "    /// Cubic ease-in-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInOutCubic\n"
    "    ease_in_out_cubic :: (float t) -> float {\n"
    "        if (t < 0.5) {\n"
    "            return 4.0 * t * t * t;\n"
    "        }\n"
    "        return 1.0 - 4.0 * (1.0 - t) * (1.0 - t) * (1.0 - t);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Easing Functions - Quartic\n"
    "    // ============================================\n"
    "\n"
    "    /// Quartic ease-in curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInQuart\n"
    "    ease_in_quart :: (float t) -> float {\n"
    "        return t * t * t * t;\n"
    "    }\n"
    "\n"
    "    /// Quartic ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutQuart\n"
    "    ease_out_quart :: (float t) -> float {\n"
    "        float u = 1.0 - t;\n"
    "        return 1.0 - u * u * u * u;\n"
    "    }\n"
    "\n"
    "    /// Quartic ease-in-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInOutQuart\n"
    "    ease_in_out_quart :: (float t) -> float {\n"
    "        if (t < 0.5) {\n"
    "            return 8.0 * t * t * t * t;\n"
    "        }\n"
    "        return 1.0 - 8.0 * (1.0 - t) * (1.0 - t) * (1.0 - t) * (1.0 - t);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Easing Functions - Exponential / Elastic / Bounce\n"
    "    // ============================================\n"
    "\n"
    "    /// Exponential ease-in curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeInExpo\n"
    "    ease_in_expo :: (float t) -> float {\n"
    "        if (t <= 0.0) {\n"
    "            return 0.0;\n"
    "        }\n"
    "        return exp2(10.0 * (t - 1.0));\n"
    "    }\n"
    "\n"
    "    /// Exponential ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutExpo\n"
    "    ease_out_expo :: (float t) -> float {\n"
    "        if (t >= 1.0) {\n"
    "            return 1.0;\n"
    "        }\n"
    "        return 1.0 - exp2(-10.0 * t);\n"
    "    }\n"
    "\n"
    "    /// Elastic ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutElastic\n"
    "    ease_out_elastic :: (float t) -> float {\n"
    "        if (t <= 0.0) {\n"
    "            return 0.0;\n"
    "        }\n"
    "        if (t >= 1.0) {\n"
    "            return 1.0;\n"
    "        }\n"
    "        return exp2(-10.0 * t) * sin((t * 10.0 - 0.75) * TAU / 3.0) + 1.0;\n"
    "    }\n"
    "\n"
    "    /// Bounce ease-out curve for t in [0, 1].\n"
    "    /// Reference: https://easings.net/#easeOutBounce\n"
    "    ease_out_bounce :: (float t) -> float {\n"
    "        float n1 = 7.5625;\n"
    "        float d1 = 2.75;\n"
    "\n"
    "        if (t < 1.0 / d1) {\n"
    "            return n1 * t * t;\n"
    "        } else if (t < 2.0 / d1) {\n"
    "            float t2 = t - 1.5 / d1;\n"
    "            return n1 * t2 * t2 + 0.75;\n"
    "        } else if (t < 2.5 / d1) {\n"
    "            float t2 = t - 2.25 / d1;\n"
    "            return n1 * t2 * t2 + 0.9375;\n"
    "        } else {\n"
    "            float t2 = t - 2.625 / d1;\n"
    "            return n1 * t2 * t2 + 0.984375;\n"
    "        }\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Periodic / Wave Functions\n"
    "    // ============================================\n"
    "\n"
    "    /// Triangle wave with period 1 and range [0, 1].\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Triangle_wave\n"
    "    triangle_wave :: (float x) -> float {\n"
    "        return abs(fract(x) * 2.0 - 1.0);\n"
    "    }\n"
    "\n"
    "    /// Sawtooth wave with period 1 and range [0, 1].\n"
    "    /// Reference: https://en.wikipedia.org/wiki/Sawtooth_wave\n"
    "    sawtooth_wave :: (float x) -> float {\n"
    "        return fract(x);\n"
    "    }\n"
    "\n"
    "    /// Sine wave remapped to [0, 1].\n"
    "    sin01 :: (float x) -> float {\n"
    "        return sin(x) * 0.5 + 0.5;\n"
    "    }\n"
    "\n"
    "    /// Cosine wave remapped to [0, 1].\n"
    "    cos01 :: (float x) -> float {\n"
    "        return cos(x) * 0.5 + 0.5;\n"
    "    }\n"
    "\n"
    "    /// Cheap sine approximation for visual effects. Best for inputs in radians.\n"
    "    fast_sin :: (float x) -> float {\n"
    "        float t = fract(x * INV_TAU);\n"
    "        float t2 = t * (1.0 - t);\n"
    "        return t2 * (t2 * 32.0 - 8.0);\n"
    "    }\n"
    "\n"
    "}\n"
    ;

static constexpr const char kNoiseSource[] =
    "module Noise {\n"
    "\n"
    "    // ============================================\n"
    "    // Constants\n"
    "    // ============================================\n"
    "    const float3 HASH_SCALE3 = float3(0.1031, 0.1030, 0.0973);\n"
    "    const float4 HASH_SCALE4 = float4(0.1031, 0.1030, 0.0973, 0.1099);\n"
    "\n"
    "    // ============================================\n"
    "    // Hash Functions (PCG-style, good distribution)\n"
    "    // ============================================\n"
    "    \n"
    "    // float -> float\n"
    "    hash11 :: (float p) -> float {\n"
    "        float3 p3 = fract(float3(p, p, p) * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yzx + 33.33);\n"
    "        return fract((p3.x + p3.y) * p3.z);\n"
    "    }\n"
    "\n"
    "    // float2 -> float\n"
    "    hash21 :: (float2 p) -> float {\n"
    "        float3 p3 = fract(float3(p.x, p.y, p.x) * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yzx + 33.33);\n"
    "        return fract((p3.x + p3.y) * p3.z);\n"
    "    }\n"
    "\n"
    "    // float3 -> float\n"
    "    hash31 :: (float3 p) -> float {\n"
    "        float3 p3 = fract(p * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yzx + 33.33);\n"
    "        return fract((p3.x + p3.y) * p3.z);\n"
    "    }\n"
    "\n"
    "    // float2 -> float2\n"
    "    hash22 :: (float2 p) -> float2 {\n"
    "        float3 p3 = fract(float3(p.x, p.y, p.x) * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yzx + 33.33);\n"
    "        return fract((p3.xx + p3.yz) * p3.zy);\n"
    "    }\n"
    "\n"
    "    // float3 -> float3\n"
    "    hash33 :: (float3 p) -> float3 {\n"
    "        float3 p3 = fract(p * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yxz + 33.33);\n"
    "        return fract((p3.xxy + p3.yxx) * p3.zyx);\n"
    "    }\n"
    "\n"
    "    // float2 -> float3 (useful for colored noise)\n"
    "    hash23 :: (float2 p) -> float3 {\n"
    "        float3 p3 = fract(float3(p.x, p.y, p.x) * HASH_SCALE3);\n"
    "        p3 += dot(p3, p3.yxz + 33.33);\n"
    "        return fract((p3.xxy + p3.yzz) * p3.zyx);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Value Noise\n"
    "    // ============================================\n"
    "    \n"
    "    value_noise_2d :: (float2 p) -> float {\n"
    "        float2 i = floor(p);\n"
    "        float2 f = fract(p);\n"
    "        \n"
    "        // Hermite interpolation (same as smoothstep)\n"
    "        float2 u = f * f * (3.0 - 2.0 * f);\n"
    "        \n"
    "        // Four corners\n"
    "        float a = hash21(i + float2(0.0, 0.0));\n"
    "        float b = hash21(i + float2(1.0, 0.0));\n"
    "        float c = hash21(i + float2(0.0, 1.0));\n"
    "        float d = hash21(i + float2(1.0, 1.0));\n"
    "        \n"
    "        // Bilinear interpolation\n"
    "        return lerp(lerp(a, b, u.x), lerp(c, d, u.x), u.y);\n"
    "    }\n"
    "\n"
    "    value_noise_3d :: (float3 p) -> float {\n"
    "        float3 i = floor(p);\n"
    "        float3 f = fract(p);\n"
    "        \n"
    "        float3 u = f * f * (3.0 - 2.0 * f);\n"
    "        \n"
    "        // Eight corners\n"
    "        float a = hash31(i + float3(0.0, 0.0, 0.0));\n"
    "        float b = hash31(i + float3(1.0, 0.0, 0.0));\n"
    "        float c = hash31(i + float3(0.0, 1.0, 0.0));\n"
    "        float d = hash31(i + float3(1.0, 1.0, 0.0));\n"
    "        float e = hash31(i + float3(0.0, 0.0, 1.0));\n"
    "        float f_ = hash31(i + float3(1.0, 0.0, 1.0));\n"
    "        float g = hash31(i + float3(0.0, 1.0, 1.0));\n"
    "        float h = hash31(i + float3(1.0, 1.0, 1.0));\n"
    "        \n"
    "        // Trilinear interpolation\n"
    "        float z0 = lerp(lerp(a, b, u.x), lerp(c, d, u.x), u.y);\n"
    "        float z1 = lerp(lerp(e, f_, u.x), lerp(g, h, u.x), u.y);\n"
    "        return lerp(z0, z1, u.z);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Gradient Noise (Perlin-style)\n"
    "    // ============================================\n"
    "    \n"
    "    gradient_noise_2d :: (float2 p) -> float {\n"
    "        float2 i = floor(p);\n"
    "        float2 f = fract(p);\n"
    "        \n"
    "        // Quintic interpolation (smoother than Hermite)\n"
    "        float2 u = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);\n"
    "        \n"
    "        // Gradients at corners\n"
    "        float2 ga = hash22(i + float2(0.0, 0.0)) * 2.0 - 1.0;\n"
    "        float2 gb = hash22(i + float2(1.0, 0.0)) * 2.0 - 1.0;\n"
    "        float2 gc = hash22(i + float2(0.0, 1.0)) * 2.0 - 1.0;\n"
    "        float2 gd = hash22(i + float2(1.0, 1.0)) * 2.0 - 1.0;\n"
    "        \n"
    "        // Vectors to corners\n"
    "        float2 pa = f - float2(0.0, 0.0);\n"
    "        float2 pb = f - float2(1.0, 0.0);\n"
    "        float2 pc = f - float2(0.0, 1.0);\n"
    "        float2 pd = f - float2(1.0, 1.0);\n"
    "        \n"
    "        // Dot products\n"
    "        float va = dot(ga, pa);\n"
    "        float vb = dot(gb, pb);\n"
    "        float vc = dot(gc, pc);\n"
    "        float vd = dot(gd, pd);\n"
    "        \n"
    "        // Bilinear interpolation\n"
    "        return lerp(lerp(va, vb, u.x), lerp(vc, vd, u.x), u.y);\n"
    "    }\n"
    "\n"
    "    gradient_noise_3d :: (float3 p) -> float {\n"
    "        float3 i = floor(p);\n"
    "        float3 f = fract(p);\n"
    "        \n"
    "        float3 u = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);\n"
    "        \n"
    "        // Gradients at 8 corners\n"
    "        float3 g000 = hash33(i + float3(0.0, 0.0, 0.0)) * 2.0 - 1.0;\n"
    "        float3 g100 = hash33(i + float3(1.0, 0.0, 0.0)) * 2.0 - 1.0;\n"
    "        float3 g010 = hash33(i + float3(0.0, 1.0, 0.0)) * 2.0 - 1.0;\n"
    "        float3 g110 = hash33(i + float3(1.0, 1.0, 0.0)) * 2.0 - 1.0;\n"
    "        float3 g001 = hash33(i + float3(0.0, 0.0, 1.0)) * 2.0 - 1.0;\n"
    "        float3 g101 = hash33(i + float3(1.0, 0.0, 1.0)) * 2.0 - 1.0;\n"
    "        float3 g011 = hash33(i + float3(0.0, 1.0, 1.0)) * 2.0 - 1.0;\n"
    "        float3 g111 = hash33(i + float3(1.0, 1.0, 1.0)) * 2.0 - 1.0;\n"
    "        \n"
    "        // Dot products\n"
    "        float v000 = dot(g000, f - float3(0.0, 0.0, 0.0));\n"
    "        float v100 = dot(g100, f - float3(1.0, 0.0, 0.0));\n"
    "        float v010 = dot(g010, f - float3(0.0, 1.0, 0.0));\n"
    "        float v110 = dot(g110, f - float3(1.0, 1.0, 0.0));\n"
    "        float v001 = dot(g001, f - float3(0.0, 0.0, 1.0));\n"
    "        float v101 = dot(g101, f - float3(1.0, 0.0, 1.0));\n"
    "        float v011 = dot(g011, f - float3(0.0, 1.0, 1.0));\n"
    "        float v111 = dot(g111, f - float3(1.0, 1.0, 1.0));\n"
    "        \n"
    "        // Trilinear interpolation\n"
    "        float z0 = lerp(lerp(v000, v100, u.x), lerp(v010, v110, u.x), u.y);\n"
    "        float z1 = lerp(lerp(v001, v101, u.x), lerp(v011, v111, u.x), u.y);\n"
    "        return lerp(z0, z1, u.z);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Worley / Cellular Noise\n"
    "    // ============================================\n"
    "    \n"
    "    // Returns (F1, F2) - distance to closest and second closest points\n"
    "    worley_2d :: (float2 p) -> float2 {\n"
    "        float2 i = floor(p);\n"
    "        float2 f = fract(p);\n"
    "        \n"
    "        float d1 = 8.0;  // Distance to closest\n"
    "        float d2 = 8.0;  // Distance to second closest\n"
    "        \n"
    "        // Search 3x3 neighborhood\n"
    "        for (int y = -1; y <= 1; y++) {\n"
    "            for (int x = -1; x <= 1; x++) {\n"
    "                float2 neighbor = float2(float(x), float(y));\n"
    "                float2 point = hash22(i + neighbor);\n"
    "                float2 diff = neighbor + point - f;\n"
    "                float dist = dot(diff, diff);\n"
    "                \n"
    "                if (dist < d1) {\n"
    "                    d2 = d1;\n"
    "                    d1 = dist;\n"
    "                } else if (dist < d2) {\n"
    "                    d2 = dist;\n"
    "                }\n"
    "            }\n"
    "        }\n"
    "        \n"
    "        return float2(sqrt(d1), sqrt(d2));\n"
    "    }\n"
    "\n"
    "    // Simple F1 only version (faster)\n"
    "    worley_2d_f1 :: (float2 p) -> float {\n"
    "        float2 i = floor(p);\n"
    "        float2 f = fract(p);\n"
    "        \n"
    "        float d1 = 8.0;\n"
    "        \n"
    "        for (int y = -1; y <= 1; y++) {\n"
    "            for (int x = -1; x <= 1; x++) {\n"
    "                float2 neighbor = float2(float(x), float(y));\n"
    "                float2 point = hash22(i + neighbor);\n"
    "                float2 diff = neighbor + point - f;\n"
    "                d1 = min(d1, dot(diff, diff));\n"
    "            }\n"
    "        }\n"
    "        \n"
    "        return sqrt(d1);\n"
    "    }\n"
    "\n"
    "    worley_3d :: (float3 p) -> float2 {\n"
    "        float3 i = floor(p);\n"
    "        float3 f = fract(p);\n"
    "        \n"
    "        float d1 = 8.0;\n"
    "        float d2 = 8.0;\n"
    "        \n"
    "        for (int z = -1; z <= 1; z++) {\n"
    "            for (int y = -1; y <= 1; y++) {\n"
    "                for (int x = -1; x <= 1; x++) {\n"
    "                    float3 neighbor = float3(float(x), float(y), float(z));\n"
    "                    float3 point = hash33(i + neighbor);\n"
    "                    float3 diff = neighbor + point - f;\n"
    "                    float dist = dot(diff, diff);\n"
    "                    \n"
    "                    if (dist < d1) {\n"
    "                        d2 = d1;\n"
    "                        d1 = dist;\n"
    "                    } else if (dist < d2) {\n"
    "                        d2 = dist;\n"
    "                    }\n"
    "                }\n"
    "            }\n"
    "        }\n"
    "        \n"
    "        return float2(sqrt(d1), sqrt(d2));\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Fractional Brownian Motion (FBM)\n"
    "    // ============================================\n"
    "    \n"
    "    fbm_2d :: (float2 p, int octaves, float lacunarity = 2.0, float gain = 0.5) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float frequency = 1.0;\n"
    "        \n"
    "        for (int i = 0; i < octaves; i++) {\n"
    "            value += amplitude * gradient_noise_2d(p * frequency);\n"
    "            frequency *= lacunarity;\n"
    "            amplitude *= gain;\n"
    "        }\n"
    "        \n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    fbm_3d :: (float3 p, int octaves, float lacunarity = 2.0, float gain = 0.5) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float frequency = 1.0;\n"
    "        \n"
    "        for (int i = 0; i < octaves; i++) {\n"
    "            value += amplitude * gradient_noise_3d(p * frequency);\n"
    "            frequency *= lacunarity;\n"
    "            amplitude *= gain;\n"
    "        }\n"
    "        \n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    // Ridged multifractal - great for mountains, lightning\n"
    "    ridged_fbm_2d :: (float2 p, int octaves, float lacunarity = 2.0, float gain = 0.5) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float frequency = 1.0;\n"
    "        float prev = 1.0;\n"
    "        \n"
    "        for (int i = 0; i < octaves; i++) {\n"
    "            float n = 1.0 - abs(gradient_noise_2d(p * frequency));\n"
    "            n = n * n;\n"
    "            value += n * amplitude * prev;\n"
    "            prev = n;\n"
    "            frequency *= lacunarity;\n"
    "            amplitude *= gain;\n"
    "        }\n"
    "        \n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    ridged_fbm_3d :: (float3 p, int octaves, float lacunarity = 2.0, float gain = 0.5) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float frequency = 1.0;\n"
    "        float prev = 1.0;\n"
    "        \n"
    "        for (int i = 0; i < octaves; i++) {\n"
    "            float n = 1.0 - abs(gradient_noise_3d(p * frequency));\n"
    "            n = n * n;\n"
    "            value += n * amplitude * prev;\n"
    "            prev = n;\n"
    "            frequency *= lacunarity;\n"
    "            amplitude *= gain;\n"
    "        }\n"
    "        \n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Domain Warping\n"
    "    // ============================================\n"
    "    \n"
    "    // Warp coordinates using noise (creates organic distortions)\n"
    "    domain_warp_2d :: (float2 p, float strength = 1.0) -> float2 {\n"
    "        float2 offset = float2(\n"
    "            gradient_noise_2d(p + float2(0.0, 0.0)),\n"
    "            gradient_noise_2d(p + float2(5.2, 1.3))\n"
    "        );\n"
    "        return p + offset * strength;\n"
    "    }\n"
    "\n"
    "    domain_warp_3d :: (float3 p, float strength = 1.0) -> float3 {\n"
    "        float3 offset = float3(\n"
    "            gradient_noise_3d(p + float3(0.0, 0.0, 0.0)),\n"
    "            gradient_noise_3d(p + float3(5.2, 1.3, 2.8)),\n"
    "            gradient_noise_3d(p + float3(2.1, 7.5, 4.6))\n"
    "        );\n"
    "        return p + offset * strength;\n"
    "    }\n"
    "\n"
    "    // Double domain warp for more complex patterns\n"
    "    domain_warp_fbm_2d :: (float2 p, int octaves = 4, float warp_strength = 0.5) -> float {\n"
    "        float2 q = float2(\n"
    "            fbm_2d(p + float2(0.0, 0.0), octaves),\n"
    "            fbm_2d(p + float2(5.2, 1.3), octaves)\n"
    "        );\n"
    "        \n"
    "        float2 r = float2(\n"
    "            fbm_2d(p + 4.0 * q + float2(1.7, 9.2), octaves),\n"
    "            fbm_2d(p + 4.0 * q + float2(8.3, 2.8), octaves)\n"
    "        );\n"
    "        \n"
    "        return fbm_2d(p + warp_strength * r, octaves);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Utility / Derived Noise\n"
    "    // ============================================\n"
    "    \n"
    "    // Turbulence (absolute value of FBM layers)\n"
    "    turbulence_2d :: (float2 p, int octaves) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float frequency = 1.0;\n"
    "        \n"
    "        for (int i = 0; i < octaves; i++) {\n"
    "            value += amplitude * abs(gradient_noise_2d(p * frequency));\n"
    "            frequency *= 2.0;\n"
    "            amplitude *= 0.5;\n"
    "        }\n"
    "        \n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    // Billowy noise (for clouds)\n"
    "    billowy_2d :: (float2 p, int octaves) -> float {\n"
    "        return 1.0 - turbulence_2d(p, octaves);\n"
    "    }\n"
    "\n"
    "    // Swiss cheese / voronoi edge noise\n"
    "    voronoi_edge_2d :: (float2 p) -> float {\n"
    "        float2 w = worley_2d(p);\n"
    "        return w.y - w.x;\n"
    "    }\n"
    "\n"
    "}\n"
    ;

static constexpr const char kPackingSource[] =
    "module Packing {\n"
    "\n"
    "import Math\n"
    "\n"
    "/// Packs RGBA color to 8-bit unsigned normalized channels using the built-in intrinsic.\n"
    "/// Reference: https://registry.khronos.org/SPIR-V/specs/unified1/GLSL.std.450.html\n"
    "pack_rgba8_unorm :: (float4 color) -> uint {\n"
    "    return pack_unorm4x8(saturate(color));\n"
    "}\n"
    "\n"
    "/// Unpacks RGBA color from 8-bit unsigned normalized channels using the built-in intrinsic.\n"
    "/// Reference: https://registry.khronos.org/SPIR-V/specs/unified1/GLSL.std.450.html\n"
    "unpack_rgba8_unorm :: (uint packed) -> float4 {\n"
    "    return unpack_unorm4x8(packed);\n"
    "}\n"
    "\n"
    "/// Packs RG color to 16-bit unsigned normalized channels using the built-in intrinsic.\n"
    "pack_rg16_unorm :: (float2 value) -> uint {\n"
    "    return pack_unorm2x16(saturate(value));\n"
    "}\n"
    "\n"
    "/// Unpacks RG color from 16-bit unsigned normalized channels using the built-in intrinsic.\n"
    "unpack_rg16_unorm :: (uint packed) -> float2 {\n"
    "    return unpack_unorm2x16(packed);\n"
    "}\n"
    "\n"
    "/// Packs RGBA values to 8-bit signed normalized channels using the built-in intrinsic.\n"
    "pack_rgba8_snorm :: (float4 value) -> uint {\n"
    "    return pack_snorm4x8(clamp(value, -1.0, 1.0));\n"
    "}\n"
    "\n"
    "/// Unpacks RGBA values from 8-bit signed normalized channels using the built-in intrinsic.\n"
    "unpack_rgba8_snorm :: (uint packed) -> float4 {\n"
    "    return unpack_snorm4x8(packed);\n"
    "}\n"
    "\n"
    "/// Packs RG values to 16-bit signed normalized channels using the built-in intrinsic.\n"
    "pack_rg16_snorm :: (float2 value) -> uint {\n"
    "    return pack_snorm2x16(clamp(value, -1.0, 1.0));\n"
    "}\n"
    "\n"
    "/// Unpacks RG values from 16-bit signed normalized channels using the built-in intrinsic.\n"
    "unpack_rg16_snorm :: (uint packed) -> float2 {\n"
    "    return unpack_snorm2x16(packed);\n"
    "}\n"
    "\n"
    "/// Packs two 32-bit floats to two IEEE 754 half-precision lanes using the built-in intrinsic.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Half-precision_floating-point_format\n"
    "pack_half2 :: (float2 value) -> uint {\n"
    "    return pack_half2x16(value);\n"
    "}\n"
    "\n"
    "/// Unpacks two IEEE 754 half-precision lanes to two 32-bit floats using the built-in intrinsic.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Half-precision_floating-point_format\n"
    "unpack_half2 :: (uint packed) -> float2 {\n"
    "    return unpack_half2x16(packed);\n"
    "}\n"
    "\n"
    "/// Folds an octahedral coordinate across the diagonal seam.\n"
    "/// Reference: https://knarkowicz.wordpress.com/2014/04/16/octahedron-normal-vector-encoding/\n"
    "oct_wrap :: (float2 v) -> float2 {\n"
    "    return (1.0 - abs(v.yx)) * float2(v.x >= 0.0 ? 1.0 : -1.0, v.y >= 0.0 ? 1.0 : -1.0);\n"
    "}\n"
    "\n"
    "/// Encodes a unit normal into octahedral 2D coordinates.\n"
    "/// Reference: https://jcgt.org/published/0003/02/01/\n"
    "encode_octahedral :: (float3 n) -> float2 {\n"
    "    float3 v = Math::safe_normalize(n);\n"
    "    v = v / (abs(v.x) + abs(v.y) + abs(v.z));\n"
    "    if (v.z < 0.0) {\n"
    "        float2 wrapped = oct_wrap(float2(v.x, v.y));\n"
    "        v.x = wrapped.x;\n"
    "        v.y = wrapped.y;\n"
    "    }\n"
    "    return float2(v.x, v.y);\n"
    "}\n"
    "\n"
    "/// Decodes octahedral 2D coordinates back to a unit normal.\n"
    "/// Reference: https://jcgt.org/published/0003/02/01/\n"
    "decode_octahedral :: (float2 e) -> float3 {\n"
    "    float3 v = float3(e.x, e.y, 1.0 - abs(e.x) - abs(e.y));\n"
    "    if (v.z < 0.0) {\n"
    "        float2 wrapped = oct_wrap(float2(v.x, v.y));\n"
    "        v.x = wrapped.x;\n"
    "        v.y = wrapped.y;\n"
    "    }\n"
    "    return Math::safe_normalize(v);\n"
    "}\n"
    "\n"
    "/// Packs a normal into two 8-bit signed normalized octahedral components.\n"
    "/// Uses a uint container for compatibility with byte-packed vertex streams.\n"
    "pack_octahedral_16 :: (float3 n) -> uint {\n"
    "    float2 e = encode_octahedral(n);\n"
    "    return pack_snorm4x8(float4(e.x, e.y, 0.0, 0.0));\n"
    "}\n"
    "\n"
    "/// Unpacks a normal from two 8-bit signed normalized octahedral components.\n"
    "unpack_octahedral_16 :: (uint packed) -> float3 {\n"
    "    float4 e = unpack_snorm4x8(packed);\n"
    "    return decode_octahedral(float2(e.x, e.y));\n"
    "}\n"
    "\n"
    "/// Packs a normal into two 16-bit signed normalized octahedral components.\n"
    "pack_octahedral_32 :: (float3 n) -> uint {\n"
    "    float2 e = encode_octahedral(n);\n"
    "    return pack_snorm2x16(e);\n"
    "}\n"
    "\n"
    "/// Unpacks a normal from two 16-bit signed normalized octahedral components.\n"
    "unpack_octahedral_32 :: (uint packed) -> float3 {\n"
    "    return decode_octahedral(unpack_snorm2x16(packed));\n"
    "}\n"
    "\n"
    "/// Packs a signed vector in [-1, 1] into 10-10-10 unsigned storage.\n"
    "/// This matches the existing vertex decompression convention in Compression.bwsl.\n"
    "pack_snorm10_10_10 :: (float3 value) -> uint {\n"
    "    float3 v = saturate(value * 0.5 + 0.5);\n"
    "    uint x = uint(v.x * 1023.0 + 0.5) & 0x3FFu;\n"
    "    uint y = uint(v.y * 1023.0 + 0.5) & 0x3FFu;\n"
    "    uint z = uint(v.z * 1023.0 + 0.5) & 0x3FFu;\n"
    "    return x | (y << 10u) | (z << 20u);\n"
    "}\n"
    "\n"
    "/// Unpacks a signed vector from 10-10-10 unsigned storage into [-1, 1].\n"
    "unpack_snorm10_10_10 :: (uint packed) -> float3 {\n"
    "    float x = float((packed >> 0u) & 0x3FFu) / 1023.0 * 2.0 - 1.0;\n"
    "    float y = float((packed >> 10u) & 0x3FFu) / 1023.0 * 2.0 - 1.0;\n"
    "    float z = float((packed >> 20u) & 0x3FFu) / 1023.0 * 2.0 - 1.0;\n"
    "    return float3(x, y, z);\n"
    "}\n"
    "\n"
    "/// Packs HDR color into Radiance-style RGBE: 8 bits per color channel plus shared exponent.\n"
    "/// Reference: https://en.wikipedia.org/wiki/RGBE_image_format\n"
    "pack_rgbe :: (float3 color) -> uint {\n"
    "    float maxChannel = max(max(color.r, color.g), color.b);\n"
    "    if (maxChannel <= 1e-9) {\n"
    "        return 0u;\n"
    "    }\n"
    "\n"
    "    float exponent = ceil(log2(maxChannel));\n"
    "    float scale = exp2(exponent) / 255.0;\n"
    "    uint r = uint(clamp(color.r / scale, 0.0, 255.0)) & 0xFFu;\n"
    "    uint g = uint(clamp(color.g / scale, 0.0, 255.0)) & 0xFFu;\n"
    "    uint b = uint(clamp(color.b / scale, 0.0, 255.0)) & 0xFFu;\n"
    "    uint e = uint(exponent + 128.0) & 0xFFu;\n"
    "    return r | (g << 8u) | (b << 16u) | (e << 24u);\n"
    "}\n"
    "\n"
    "/// Unpacks Radiance-style RGBE color into linear HDR RGB.\n"
    "/// Reference: https://en.wikipedia.org/wiki/RGBE_image_format\n"
    "unpack_rgbe :: (uint packed) -> float3 {\n"
    "    uint e = (packed >> 24u) & 0xFFu;\n"
    "    if (e == 0u) {\n"
    "        return float3(0.0);\n"
    "    }\n"
    "\n"
    "    float scale = exp2(float(e) - 128.0) / 255.0;\n"
    "    float r = float(packed & 0xFFu) * scale;\n"
    "    float g = float((packed >> 8u) & 0xFFu) * scale;\n"
    "    float b = float((packed >> 16u) & 0xFFu) * scale;\n"
    "    return float3(r, g, b);\n"
    "}\n"
    "\n"
    "/// Encodes HDR color into RGBM with a caller-provided max range.\n"
    "/// Reference: https://graphicrants.blogspot.com/2009/04/rgbm-color-encoding.html\n"
    "encode_rgbm :: (float3 color, float maxRange) -> float4 {\n"
    "    float maxChannel = max(max(color.r, color.g), color.b);\n"
    "    float m = clamp(ceil(maxChannel / maxRange * 255.0) / 255.0, 1.0 / 255.0, 1.0);\n"
    "    return float4(color / (m * maxRange), m);\n"
    "}\n"
    "\n"
    "/// Decodes RGBM color with the same max range used for encoding.\n"
    "/// Reference: https://graphicrants.blogspot.com/2009/04/rgbm-color-encoding.html\n"
    "decode_rgbm :: (float4 rgbm, float maxRange) -> float3 {\n"
    "    return rgbm.rgb * rgbm.a * maxRange;\n"
    "}\n"
    "\n"
    "}\n"
    ;

static constexpr const char kPBRSource[] =
    "module PBR {\n"
    "    \n"
    "import Math\n"
    "\n"
    "struct PBRMaterial {\n"
    "    float3 albedo;\n"
    "    float roughness;\n"
    "    float metallic;\n"
    "    float ao;\n"
    "};\n"
    "\n"
    "\n"
    "// Fresnel-Schlick Approximation\n"
    " fresnelSchlick :: (float cosTheta, float3 F0) -> float3 {\n"
    "\n"
    "    return F0 + (1.0 - F0) * pow(1.0 - cosTheta, 5.0);\n"
    "\n"
    "}\n"
    "\n"
    "// UE4 Optimized Fresnel\n"
    " fresnelSchlickUE4 :: (float VdotH, float3 F0) -> float3 {\n"
    "\n"
    "    return F0 + (1.0 - F0) * pow(2.0, (-5.55473 * VdotH - 6.98316) * VdotH);\n"
    "\n"
    "}\n"
    "\n"
    "// GGX/Trowbridge-Reitz Normal Distribution Function\n"
    " distributionGGX :: (float NdotH, float roughness) -> float {\n"
    "\n"
    "    float alpha = roughness * roughness;\n"
    "    float alphaSqr = alpha * alpha;\n"
    "    float denom = NdotH * NdotH * (alphaSqr - 1.0) + 1.0;\n"
    "    return alphaSqr / (Math::PI * denom * denom);\n"
    "\n"
    "}\n"
    "\n"
    "// Smith's Geometry Function (Schlick-GGX)\n"
    " geometrySchlickGGX :: (float NdotV, float roughness) -> float {\n"
    "\n"
    "    float k = (roughness + 1.0) * (roughness + 1.0) / 8.0;\n"
    "    return NdotV / (NdotV * (1.0 - k) + k);\n"
    "\n"
    "}\n"
    "\n"
    "geometrySmith :: (float NdotV, float NdotL, float roughness) -> float {\n"
    "\n"
    "    float ggx1 = geometrySchlickGGX(NdotV, roughness);\n"
    "    float ggx2 = geometrySchlickGGX(NdotL, roughness);\n"
    "    return ggx1 * ggx2;\n"
    "\n"
    "}\n"
    "\n"
    "\n"
    "// --------------------------- Direct Lighting --------------------------------\n"
    "\n"
    "// Complete Cook-Torrance Specular BRDF\n"
    "cookTorranceSpecular :: (float3 N, float3 V, float3 L, float3 F, float roughness) -> float3 {\n"
    "\n"
    "    float3 H = normalize(V + L);\n"
    "    float NdotH = max(dot(N, H), 0.0);\n"
    "    float NdotV = max(dot(N, V), 0.0);\n"
    "    float NdotL = max(dot(N, L), 0.0);\n"
    "    \n"
    "    float D = distributionGGX(NdotH, roughness);\n"
    "    float G = geometrySmith(NdotV, NdotL, roughness);\n"
    "    \n"
    "    float3 numerator = D * F * G;\n"
    "    float denominator = 4.0 * NdotV * NdotL + 0.001; // Prevent divide by zero\n"
    "    \n"
    "    return numerator / denominator;\n"
    "\n"
    "}\n"
    "\n"
    "// Lambertian Diffuse\n"
    "lambertianDiffuse :: (float3 albedo) -> float3 {\n"
    "\n"
    "    return albedo / Math::PI;\n"
    "\n"
    "}\n"
    "\n"
    "// Complete Direct Lighting Calculation\n"
    "calculateDirectLighting :: (PBRMaterial mat, float3 N, float3 V, float3 L, float3 radiance) -> float3 {\n"
    "\n"
    "    float NdotL = max(dot(N, L), 0.0);\n"
    "    float3 H = normalize(V + L);\n"
    "    float VdotH = max(dot(V, H), 0.0);\n"
    "    \n"
    "    // Calculate Fresnel at interface\n"
    "    float3 F0 = lerp(float3(0.04), mat.albedo, mat.metallic);\n"
    "    float3 F = fresnelSchlickUE4(VdotH, F0);\n"
    "    \n"
    "    // Energy conservation: metals don't have diffuse reflection\n"
    "    float3 kD = (1.0 - F) * (1.0 - mat.metallic);\n"
    "    \n"
    "    // Diffuse component\n"
    "    float3 diffuse = kD * lambertianDiffuse(mat.albedo);\n"
    "    \n"
    "    // Specular component\n"
    "    float3 specular = cookTorranceSpecular(N, V, L, F, mat.roughness);\n"
    "    \n"
    "    // Combine and apply radiance\n"
    "    return (diffuse + specular) * radiance * NdotL;\n"
    "\n"
    "}\n"
    "\n"
    "// --------------------------- Image Based Lighting (IBL) -------------------------\n"
    "\n"
    "// IBL Diffuse (Irradiance)\n"
    "calculateIBLDiffuse :: (samplerCube irradianceMap, float3 N, float3 albedo, float metallic) -> float3 {\n"
    "\n"
    "    float3 irradiance = textureCube(irradianceMap, N).rgb;\n"
    "    return irradiance * albedo * (1.0 - metallic);\n"
    "\n"
    "}\n"
    "\n"
    "// IBL Specular (Pre-filtered Environment + BRDF LUT)\n"
    "calculateIBLSpecular :: (samplerCube prefilterMap, sampler2D brdfLUT, float3 N, float3 V, float3 albedo, float roughness, float metallic) -> float3 {\n"
    "\n"
    "    float3 R = reflect(-V, N);\n"
    "    float NdotV = max(dot(N, V), 0.0);\n"
    "    \n"
    "    // Sample pre-filtered environment map at appropriate mip level\n"
    "    float3 prefilteredColor = textureCubeLod(prefilterMap, R, roughness * 4.0).rgb; // Todo: add textureCubeLod\n"
    "    \n"
    "    // Sample BRDF integration map\n"
    "    float2 brdf = sample(brdfLUT, float2(NdotV, roughness)).rg;\n"
    "    \n"
    "    // Calculate F0 (surface reflection at zero incidence)\n"
    "    float3 F0 = lerp(float3(0.04), albedo, metallic);\n"
    "    \n"
    "    // Fresnel for IBL\n"
    "    float3 F = F0 + (1.0 - F0) * pow(1.0 - NdotV, 5.0);\n"
    "    \n"
    "    // Combine prefiltered color with BRDF terms\n"
    "    return prefilteredColor * (F * brdf.x + brdf.y);\n"
    "\n"
    "}\n"
    "\n"
    "// Complete IBL Calculation\n"
    " calculateIBL :: (samplerCube irradianceMap, samplerCube prefilterMap, sampler2D brdfLUT, PBRMaterial mat, float3 N, float3 V) -> float3 {\n"
    "\n"
    "    float3 diffuse = calculateIBLDiffuse(irradianceMap, N, mat.albedo, mat.metallic);\n"
    "    float3 specular = calculateIBLSpecular(prefilterMap, brdfLUT, N, V, mat.albedo, mat.roughness, mat.metallic);\n"
    "    \n"
    "    // Apply ambient occlusion\n"
    "    return (diffuse + specular) * mat.ao;\n"
    "\n"
    "}\n"
    "    \n"
    "}"
    ;

static constexpr const char kPostFXSource[] =
    "\n"
    "module PostFX {\n"
    "\n"
    "// Gamma correction\n"
    "gammaCorrect :: (float3 color) -> float3 {\n"
    "    return pow(color, 2.2);\n"
    "}\n"
    "\n"
    "inverseGammaCorrect :: (float3 color) -> float3 {\n"
    "    return pow(color, 1.0 / 2.2);\n"
    "}\n"
    "\n"
    "linearToSRGB :: (float3 color) -> float3 {\n"
    "    return inverseGammaCorrect(color);\n"
    "}\n"
    "\n"
    "sRGBToLinear :: (float3 color) -> float3 {\n"
    "    return gammaCorrect(color);\n"
    "}\n"
    "\n"
    "// ACES Tone Mapping\n"
    "ACESFilm :: (float3 x) -> float3 {\n"
    "    const float a = 2.51;\n"
    "    const float b = 0.03;\n"
    "    const float c = 2.43;\n"
    "    const float d = 0.59;\n"
    "    const float e = 0.14;\n"
    "    return clamp((x * (a * x + b)) / (x * (c * x + d) + e), 0.0, 1.0);\n"
    "}\n"
    "\n"
    "reinhardToneMap :: (float3 color) -> float3 {\n"
    "    return color / (color + float3(1.0));\n"
    "}\n"
    "\n"
    "reinhardExtendedToneMap :: (float3 color, float maxWhite) -> float3 {\n"
    "    float3 numerator = color * (1.0 + color / (maxWhite * maxWhite));\n"
    "    return numerator / (1.0 + color);\n"
    "}\n"
    "\n"
    "}\n"
    ;

static constexpr const char kRandomSource[] =
    "// Random Number Generation Module for BWSL\n"
    "// GPU-friendly hash-based random number generation\n"
    "//\n"
    "// For animation/time-based randomness, pass time or frame count as part of the seed.\n"
    "\n"
    "module Random {\n"
    "\n"
    "    // ============================================\n"
    "    // Constants\n"
    "    // ============================================\n"
    "    const uint GOLDEN_RATIO = 0x9E3779B9u;\n"
    "    const uint PCG_MULT = 0x5851F42Du;\n"
    "    const uint PCG_INC = 0x14057B7Eu;\n"
    "    const float INV_UINT_MAX = 2.3283064365386963e-10;  // 1.0 / (2^32 - 1)\n"
    "\n"
    "    // ============================================\n"
    "    // Core Hash Functions\n"
    "    // ============================================\n"
    "\n"
    "    // PCG-style hash - fast, good quality\n"
    "    // Based on PCG (Permuted Congruential Generator)\n"
    "    pcg_hash :: (uint seed) -> uint {\n"
    "        uint state = seed * PCG_MULT + PCG_INC;\n"
    "        uint word = ((state >> ((state >> 28u) + 4u)) ^ state) * 277803737u;\n"
    "        return (word >> 22u) ^ word;\n"
    "    }\n"
    "\n"
    "    // Wang hash - simple and fast, good for spatial hashing\n"
    "    wang_hash :: (uint seed) -> uint {\n"
    "        uint x = seed;\n"
    "        x = (x ^ 61u) ^ (x >> 16u);\n"
    "        x = x * 9u;\n"
    "        x = x ^ (x >> 4u);\n"
    "        x = x * 0x27D4EB2Du;\n"
    "        x = x ^ (x >> 15u);\n"
    "        return x;\n"
    "    }\n"
    "\n"
    "    // xxHash-inspired single round - very fast\n"
    "    xxhash :: (uint seed) -> uint {\n"
    "        uint h = seed + 0x165667B1u;\n"
    "        h = h * 0x85EBCA77u;\n"
    "        h = h ^ (h >> 13u);\n"
    "        h = h * 0xC2B2AE3Du;\n"
    "        h = h ^ (h >> 16u);\n"
    "        return h;\n"
    "    }\n"
    "\n"
    "    // Combine two seeds into one (for multi-dimensional seeding)\n"
    "    hash_combine :: (uint a, uint b) -> uint {\n"
    "        return a ^ (b + GOLDEN_RATIO + (a << 6u) + (a >> 2u));\n"
    "    }\n"
    "\n"
    "    // Hash a 2D coordinate to a single uint\n"
    "    hash2d :: (uint x, uint y) -> uint {\n"
    "        return pcg_hash(hash_combine(x, y));\n"
    "    }\n"
    "\n"
    "    // Hash a 3D coordinate to a single uint\n"
    "    hash3d :: (uint x, uint y, uint z) -> uint {\n"
    "        return pcg_hash(hash_combine(hash_combine(x, y), z));\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Float Conversion (uint -> [0,1) range)\n"
    "    // ============================================\n"
    "\n"
    "    // Convert uint hash to float in [0, 1)\n"
    "    uint_to_float :: (uint h) -> float {\n"
    "        return float(h) * INV_UINT_MAX;\n"
    "    }\n"
    "\n"
    "    // Convert uint hash to float in [lo, hi)\n"
    "    uint_to_float_range :: (uint h, float lo, float hi) -> float {\n"
    "        return lo + (hi - lo) * uint_to_float(h);\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Random Float Generation\n"
    "    // ============================================\n"
    "\n"
    "    // Generate random float [0, 1) from seed\n"
    "    rand :: (uint seed) -> float {\n"
    "        return uint_to_float(pcg_hash(seed));\n"
    "    }\n"
    "\n"
    "    // Generate random float in [lo, hi) from seed\n"
    "    rand_range :: (uint seed, float lo, float hi) -> float {\n"
    "        return uint_to_float_range(pcg_hash(seed), lo, hi);\n"
    "    }\n"
    "\n"
    "    // Generate random float [0, 1) from 2D position (good for textures/UV)\n"
    "    rand2d :: (float2 uv, uint seed) -> float {\n"
    "        uint2 p = uint2(uint(uv.x * 65536.0), uint(uv.y * 65536.0));\n"
    "        return uint_to_float(hash3d(p.x, p.y, seed));\n"
    "    }\n"
    "\n"
    "    // Generate random float [0, 1) from 3D position\n"
    "    rand3d :: (float3 pos, uint seed) -> float {\n"
    "        uint3 p = uint3(uint(pos.x * 65536.0), uint(pos.y * 65536.0), uint(pos.z * 65536.0));\n"
    "        return uint_to_float(hash_combine(hash3d(p.x, p.y, p.z), seed));\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Random Vector Generation\n"
    "    // ============================================\n"
    "\n"
    "    // Generate random float2 in [0, 1) x [0, 1)\n"
    "    rand_float2 :: (uint seed) -> float2 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "        return float2(uint_to_float(h1), uint_to_float(h2));\n"
    "    }\n"
    "\n"
    "    // Generate random float3 in [0, 1) x [0, 1) x [0, 1)\n"
    "    rand_float3 :: (uint seed) -> float3 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "        uint h3 = pcg_hash(h2);\n"
    "        return float3(uint_to_float(h1), uint_to_float(h2), uint_to_float(h3));\n"
    "    }\n"
    "\n"
    "    // Generate random float4 in [0, 1)^4\n"
    "    rand_float4 :: (uint seed) -> float4 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "        uint h3 = pcg_hash(h2);\n"
    "        uint h4 = pcg_hash(h3);\n"
    "        return float4(uint_to_float(h1), uint_to_float(h2), uint_to_float(h3), uint_to_float(h4));\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Geometric Random Distributions\n"
    "    // ============================================\n"
    "\n"
    "    // Random point uniformly distributed in unit circle\n"
    "    rand_in_circle :: (uint seed) -> float2 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "\n"
    "        float angle = uint_to_float(h1) * 6.28318530718;  // TAU\n"
    "        float r = sqrt(uint_to_float(h2));  // sqrt for uniform area distribution\n"
    "\n"
    "        return float2(r * cos(angle), r * sin(angle));\n"
    "    }\n"
    "\n"
    "    // Random point on unit circle (edge only)\n"
    "    rand_on_circle :: (uint seed) -> float2 {\n"
    "        float angle = uint_to_float(pcg_hash(seed)) * 6.28318530718;\n"
    "        return float2(cos(angle), sin(angle));\n"
    "    }\n"
    "\n"
    "    // Random point uniformly distributed in unit sphere\n"
    "    rand_in_sphere :: (uint seed) -> float3 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "        uint h3 = pcg_hash(h2);\n"
    "\n"
    "        float theta = uint_to_float(h1) * 6.28318530718;  // TAU\n"
    "        float phi = acos(2.0 * uint_to_float(h2) - 1.0);   // Uniform on sphere surface\n"
    "        float r = pow(uint_to_float(h3), 0.333333333);     // Cube root for uniform volume\n"
    "\n"
    "        float sin_phi = sin(phi);\n"
    "        return float3(\n"
    "            r * sin_phi * cos(theta),\n"
    "            r * sin_phi * sin(theta),\n"
    "            r * cos(phi)\n"
    "        );\n"
    "    }\n"
    "\n"
    "    // Random direction on unit sphere surface (for random directions)\n"
    "    rand_direction :: (uint seed) -> float3 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "\n"
    "        float theta = uint_to_float(h1) * 6.28318530718;\n"
    "        float phi = acos(2.0 * uint_to_float(h2) - 1.0);\n"
    "\n"
    "        float sin_phi = sin(phi);\n"
    "        return float3(\n"
    "            sin_phi * cos(theta),\n"
    "            sin_phi * sin(theta),\n"
    "            cos(phi)\n"
    "        );\n"
    "    }\n"
    "\n"
    "    // Random direction in hemisphere around normal\n"
    "    rand_hemisphere :: (uint seed, float3 normal) -> float3 {\n"
    "        float3 dir = rand_direction(seed);\n"
    "        // Flip if pointing away from normal\n"
    "        if (dot(dir, normal) < 0.0) {\n"
    "            return -dir;\n"
    "        }\n"
    "        return dir;\n"
    "    }\n"
    "\n"
    "    // Cosine-weighted hemisphere sampling (for diffuse lighting)\n"
    "    rand_cosine_hemisphere :: (uint seed, float3 normal) -> float3 {\n"
    "        uint h1 = pcg_hash(seed);\n"
    "        uint h2 = pcg_hash(h1);\n"
    "\n"
    "        float r1 = uint_to_float(h1);\n"
    "        float r2 = uint_to_float(h2);\n"
    "\n"
    "        float phi = 6.28318530718 * r1;\n"
    "        float cos_theta = sqrt(r2);\n"
    "        float sin_theta = sqrt(1.0 - r2);\n"
    "\n"
    "        // Build orthonormal basis\n"
    "        float3 up = abs(normal.z) < 0.999 ? float3(0.0, 0.0, 1.0) : float3(1.0, 0.0, 0.0);\n"
    "        float3 tangent = normalize(cross(up, normal));\n"
    "        float3 bitangent = cross(normal, tangent);\n"
    "\n"
    "        return tangent * cos(phi) * sin_theta +\n"
    "               bitangent * sin(phi) * sin_theta +\n"
    "               normal * cos_theta;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Probability Functions\n"
    "    // ============================================\n"
    "\n"
    "    // Returns true with probability p (0.0 to 1.0)\n"
    "    chance :: (uint seed, float p) -> bool {\n"
    "        return rand(seed) < p;\n"
    "    }\n"
    "\n"
    "    // Returns index [0, count) with uniform probability\n"
    "    rand_index :: (uint seed, uint count) -> uint {\n"
    "        return pcg_hash(seed) % count;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Noise-like Functions (coherent random)\n"
    "    // ============================================\n"
    "\n"
    "    // Value noise - returns smooth random in [0, 1] from 2D position\n"
    "    // Good for procedural textures\n"
    "    value_noise :: (float2 p) -> float {\n"
    "        float2 i = floor(p);\n"
    "        float2 f = fract(p);\n"
    "\n"
    "        // Smooth interpolation\n"
    "        float2 u = f * f * (3.0 - 2.0 * f);\n"
    "\n"
    "        // Hash corners\n"
    "        uint2 pi = uint2(uint(i.x), uint(i.y));\n"
    "        float a = rand(hash2d(pi.x, pi.y));\n"
    "        float b = rand(hash2d(pi.x + 1u, pi.y));\n"
    "        float c = rand(hash2d(pi.x, pi.y + 1u));\n"
    "        float d = rand(hash2d(pi.x + 1u, pi.y + 1u));\n"
    "\n"
    "        // Bilinear interpolation\n"
    "        return lerp(lerp(a, b, u.x), lerp(c, d, u.x), u.y);\n"
    "    }\n"
    "\n"
    "    // Value noise 3D (use distinct name to avoid overload resolution issues across modules)\n"
    "    value_noise3d :: (float3 p) -> float {\n"
    "        float3 i = floor(p);\n"
    "        float3 f = fract(p);\n"
    "\n"
    "        // Smooth interpolation\n"
    "        float3 u = f * f * (3.0 - 2.0 * f);\n"
    "\n"
    "        uint3 pi = uint3(uint(i.x), uint(i.y), uint(i.z));\n"
    "\n"
    "        // Hash 8 corners and trilinear interpolate\n"
    "        float c000 = rand(hash3d(pi.x, pi.y, pi.z));\n"
    "        float c100 = rand(hash3d(pi.x + 1u, pi.y, pi.z));\n"
    "        float c010 = rand(hash3d(pi.x, pi.y + 1u, pi.z));\n"
    "        float c110 = rand(hash3d(pi.x + 1u, pi.y + 1u, pi.z));\n"
    "        float c001 = rand(hash3d(pi.x, pi.y, pi.z + 1u));\n"
    "        float c101 = rand(hash3d(pi.x + 1u, pi.y, pi.z + 1u));\n"
    "        float c011 = rand(hash3d(pi.x, pi.y + 1u, pi.z + 1u));\n"
    "        float c111 = rand(hash3d(pi.x + 1u, pi.y + 1u, pi.z + 1u));\n"
    "\n"
    "        float x00 = lerp(c000, c100, u.x);\n"
    "        float x10 = lerp(c010, c110, u.x);\n"
    "        float x01 = lerp(c001, c101, u.x);\n"
    "        float x11 = lerp(c011, c111, u.x);\n"
    "\n"
    "        float y0 = lerp(x00, x10, u.y);\n"
    "        float y1 = lerp(x01, x11, u.y);\n"
    "\n"
    "        return lerp(y0, y1, u.z);\n"
    "    }\n"
    "\n"
    "    // Fractal Brownian Motion (fBm) - layered noise for natural textures\n"
    "    fbm :: (float2 p, uint octaves) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float2 pos = p;\n"
    "\n"
    "        foreach (i in 0..octaves) {\n"
    "            value += amplitude * value_noise(pos);\n"
    "            pos = pos * 2.0;\n"
    "            amplitude = amplitude * 0.5;\n"
    "        }\n"
    "\n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    // 3D fBm (use distinct name to avoid overload resolution issues across modules)\n"
    "    fbm3d :: (float3 p, uint octaves) -> float {\n"
    "        float value = 0.0;\n"
    "        float amplitude = 0.5;\n"
    "        float3 pos = p;\n"
    "\n"
    "        foreach (i in 0..octaves) {\n"
    "            value += amplitude * value_noise3d(pos);\n"
    "            pos = pos * 2.0;\n"
    "            amplitude = amplitude * 0.5;\n"
    "        }\n"
    "\n"
    "        return value;\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Utility: Sequence Generation\n"
    "    // ============================================\n"
    "\n"
    "    // Get Nth value in a random sequence (for particle systems, etc.)\n"
    "    // Each call with same base_seed and different index gives different but deterministic value\n"
    "    sequence :: (uint base_seed, uint index) -> float {\n"
    "        return rand(hash_combine(base_seed, index));\n"
    "    }\n"
    "\n"
    "    // Get Nth float3 in a sequence\n"
    "    sequence_float3 :: (uint base_seed, uint index) -> float3 {\n"
    "        return rand_float3(hash_combine(base_seed, index));\n"
    "    }\n"
    "\n"
    "    // ============================================\n"
    "    // Blue Noise Approximation\n"
    "    // ============================================\n"
    "\n"
    "    // Interleaved gradient noise - good for dithering, less banding than white noise\n"
    "    // From Jimenez 2014 \"Next Generation Post Processing in Call of Duty\"\n"
    "    interleaved_gradient :: (float2 screen_pos) -> float {\n"
    "        float3 magic = float3(0.06711056, 0.00583715, 52.9829189);\n"
    "        return fract(magic.z * fract(dot(screen_pos, magic.xy)));\n"
    "    }\n"
    "\n"
    "    // R2 sequence - low discrepancy quasi-random for better distribution\n"
    "    // Good for sampling patterns\n"
    "    r2_sequence :: (uint index) -> float2 {\n"
    "        const float g = 1.32471795724;  // Plastic constant\n"
    "        const float a1 = 1.0 / g;\n"
    "        const float a2 = 1.0 / (g * g);\n"
    "        return fract(float2(0.5) + float(index) * float2(a1, a2));\n"
    "    }\n"
    "\n"
    "}\n"
    ;

static constexpr const char kSamplingSource[] =
    "module Sampling {\n"
    "\n"
    "import Math\n"
    "import Random\n"
    "import Spaces\n"
    "\n"
    "const float INV_UINT_MAX = 2.3283064365386963e-10;\n"
    "\n"
    "/// Computes the base-2 Van der Corput radical inverse using bit reversal.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Van_der_Corput_sequence\n"
    "radical_inverse_vdc :: (uint bits) -> float {\n"
    "    return float(reverse_bits(bits)) * INV_UINT_MAX;\n"
    "}\n"
    "\n"
    "/// Returns a 2D Hammersley point for quasi-Monte Carlo sampling.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Low-discrepancy_sequence\n"
    "hammersley :: (uint index, uint count) -> float2 {\n"
    "    return float2(float(index) / max(float(count), 1.0), radical_inverse_vdc(index));\n"
    "}\n"
    "\n"
    "/// Returns the R2 low-discrepancy sequence point based on the plastic constant.\n"
    "/// Reference: http://extremelearning.com.au/unreasonable-effectiveness-of-quasirandom-sequences/\n"
    "r2 :: (uint index) -> float2 {\n"
    "    float g = 1.32471795724;\n"
    "    float a1 = 1.0 / g;\n"
    "    float a2 = 1.0 / (g * g);\n"
    "    return fract(float2(0.5) + float(index) * float2(a1, a2));\n"
    "}\n"
    "\n"
    "/// Returns a deterministic random 2D sample from a seed and sequence index.\n"
    "seeded_2d :: (uint seed, uint index) -> float2 {\n"
    "    uint s = Random::hash_combine(seed, index);\n"
    "    return Random::rand_float2(s);\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a uniform disk sample.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Polar_coordinate_system\n"
    "uniform_disk :: (float2 xi) -> float2 {\n"
    "    float r = sqrt(xi.x);\n"
    "    float phi = Math::TAU * xi.y;\n"
    "    return float2(r * cos(phi), r * sin(phi));\n"
    "}\n"
    "\n"
    "/// Maps a scalar sample to a point on the unit circle.\n"
    "uniform_circle :: (float xi) -> float2 {\n"
    "    float phi = Math::TAU * xi;\n"
    "    return float2(cos(phi), sin(phi));\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a direction uniformly distributed on the unit sphere.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Sphere#Spherical_coordinates\n"
    "uniform_sphere :: (float2 xi) -> float3 {\n"
    "    float z = 1.0 - 2.0 * xi.x;\n"
    "    float r = sqrt(max(0.0, 1.0 - z * z));\n"
    "    float phi = Math::TAU * xi.y;\n"
    "    return float3(r * cos(phi), r * sin(phi), z);\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a local +Z hemisphere direction.\n"
    "uniform_hemisphere_z :: (float2 xi) -> float3 {\n"
    "    float z = xi.x;\n"
    "    float r = sqrt(max(0.0, 1.0 - z * z));\n"
    "    float phi = Math::TAU * xi.y;\n"
    "    return float3(r * cos(phi), r * sin(phi), z);\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a cosine-weighted local +Z hemisphere direction.\n"
    "/// Reference: https://www.pbr-book.org/4ed/Sampling_Algorithms/Sampling_Multidimensional_Functions\n"
    "cosine_hemisphere_z :: (float2 xi) -> float3 {\n"
    "    float2 d = uniform_disk(xi);\n"
    "    float z = sqrt(max(0.0, 1.0 - dot(d, d)));\n"
    "    return float3(d.x, d.y, z);\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a world-space hemisphere direction around normal.\n"
    "uniform_hemisphere :: (float2 xi, float3 normal) -> float3 {\n"
    "    Spaces::Basis basis = Spaces::make_basis(normal);\n"
    "    return Spaces::tangent_to_world(uniform_hemisphere_z(xi), basis);\n"
    "}\n"
    "\n"
    "/// Maps a uniform square sample to a cosine-weighted world-space hemisphere direction around normal.\n"
    "cosine_hemisphere :: (float2 xi, float3 normal) -> float3 {\n"
    "    Spaces::Basis basis = Spaces::make_basis(normal);\n"
    "    return Spaces::tangent_to_world(cosine_hemisphere_z(xi), basis);\n"
    "}\n"
    "\n"
    "/// Samples a GGX/Trowbridge-Reitz half vector in local +Z space.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Specular_highlight#Microfacet_models\n"
    "/// Background: https://pharr.org/matt/blog/2022/05/06/trowbridge-reitz.html\n"
    "ggx_half_vector_z :: (float2 xi, float roughness) -> float3 {\n"
    "    float a = max(roughness * roughness, Math::EPSILON);\n"
    "    float a2 = a * a;\n"
    "    float phi = Math::TAU * xi.x;\n"
    "    float cosTheta = sqrt((1.0 - xi.y) / (1.0 + (a2 - 1.0) * xi.y));\n"
    "    float sinTheta = sqrt(max(0.0, 1.0 - cosTheta * cosTheta));\n"
    "    return float3(sinTheta * cos(phi), sinTheta * sin(phi), cosTheta);\n"
    "}\n"
    "\n"
    "/// Samples a GGX/Trowbridge-Reitz half vector around a world-space normal.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Specular_highlight#Microfacet_models\n"
    "ggx_half_vector :: (float2 xi, float roughness, float3 normal) -> float3 {\n"
    "    Spaces::Basis basis = Spaces::make_basis(normal);\n"
    "    return Spaces::tangent_to_world(ggx_half_vector_z(xi, roughness), basis);\n"
    "}\n"
    "\n"
    "/// Returns the PDF for cosine-weighted hemisphere sampling.\n"
    "cosine_hemisphere_pdf :: (float cosTheta) -> float {\n"
    "    return max(cosTheta, 0.0) * Math::INV_PI;\n"
    "}\n"
    "\n"
    "/// Returns the constant PDF for uniform sphere sampling.\n"
    "uniform_sphere_pdf :: () -> float {\n"
    "    return 1.0 / (4.0 * Math::PI);\n"
    "}\n"
    "\n"
    "/// Returns the constant PDF for uniform hemisphere sampling.\n"
    "uniform_hemisphere_pdf :: () -> float {\n"
    "    return 1.0 / (2.0 * Math::PI);\n"
    "}\n"
    "\n"
    "/// Evaluates the GGX/Trowbridge-Reitz normal distribution function.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Specular_highlight#Microfacet_models\n"
    "ggx_ndf :: (float NdotH, float roughness) -> float {\n"
    "    float a = max(roughness * roughness, Math::EPSILON);\n"
    "    float a2 = a * a;\n"
    "    float denom = NdotH * NdotH * (a2 - 1.0) + 1.0;\n"
    "    return a2 / max(Math::PI * denom * denom, Math::EPSILON);\n"
    "}\n"
    "\n"
    "/// Returns the reflected-direction PDF for GGX half-vector sampling.\n"
    "ggx_reflection_pdf :: (float NdotH, float VdotH, float roughness) -> float {\n"
    "    float d = ggx_ndf(max(NdotH, 0.0), roughness);\n"
    "    return d * max(NdotH, 0.0) / max(4.0 * max(VdotH, 0.0), Math::EPSILON);\n"
    "}\n"
    "\n"
    "}\n"
    ;

static constexpr const char kSDFSource[] =
    "module SDF {\n"
    "\n"
    "import Math\n"
    "\n"
    "/// A ray with origin and normalized direction.\n"
    "struct Ray {\n"
    "    float3 origin;\n"
    "    float3 direction;\n"
    "};\n"
    "\n"
    "/// Result returned by raymarch helpers.\n"
    "struct RaymarchResult {\n"
    "    bool hit;\n"
    "    int steps;\n"
    "    float distance;\n"
    "    float3 position;\n"
    "    float surfaceDistance;\n"
    "};\n"
    "\n"
    "// ============================================\n"
    "// Primitive Distance Functions\n"
    "// ============================================\n"
    "\n"
    "/// Distance to a sphere centered at the origin.\n"
    "/// Reference: https://iquilezles.org/articles/distfunctions/\n"
    "sd_sphere :: (float3 p, float radius) -> float {\n"
    "    return length(p) - radius;\n"
    "}\n"
    "\n"
    "/// Distance to an axis-aligned box centered at the origin.\n"
    "/// halfExtents is the positive half-size along each axis.\n"
    "/// Reference: https://iquilezles.org/articles/distfunctions/\n"
    "sd_box :: (float3 p, float3 halfExtents) -> float {\n"
    "    float3 q = abs(p) - halfExtents;\n"
    "    float outside = length(max(q, 0.0));\n"
    "    float inside = min(max(q.x, max(q.y, q.z)), 0.0);\n"
    "    return outside + inside;\n"
    "}\n"
    "\n"
    "/// Distance to a rounded axis-aligned box centered at the origin.\n"
    "/// Reference: https://iquilezles.org/articles/distfunctions/\n"
    "sd_round_box :: (float3 p, float3 halfExtents, float radius) -> float {\n"
    "    return sd_box(p, halfExtents) - radius;\n"
    "}\n"
    "\n"
    "/// Distance to a torus centered at the origin and aligned around the Y axis.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Torus\n"
    "sd_torus :: (float3 p, float majorRadius, float minorRadius) -> float {\n"
    "    float2 q = float2(length(p.xz) - majorRadius, p.y);\n"
    "    return length(q) - minorRadius;\n"
    "}\n"
    "\n"
    "/// Distance to a capsule segment from a to b with radius.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Capsule_(geometry)\n"
    "sd_capsule :: (float3 p, float3 a, float3 b, float radius) -> float {\n"
    "    float3 pa = p - a;\n"
    "    float3 ba = b - a;\n"
    "    float h = clamp(dot(pa, ba) / max(dot(ba, ba), Math::EPSILON), 0.0, 1.0);\n"
    "    return length(pa - ba * h) - radius;\n"
    "}\n"
    "\n"
    "/// Distance to a vertical cylinder centered at the origin and aligned to the Y axis.\n"
    "/// radius controls XZ radius; halfHeight controls positive/negative Y extent.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Cylinder\n"
    "sd_cylinder :: (float3 p, float radius, float halfHeight) -> float {\n"
    "    float2 d = abs(float2(length(p.xz), p.y)) - float2(radius, halfHeight);\n"
    "    return min(max(d.x, d.y), 0.0) + length(max(d, 0.0));\n"
    "}\n"
    "\n"
    "/// Distance to a plane where dot(p, normal) + offset = 0.\n"
    "/// normal is normalized internally for predictable distances.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Plane_(geometry)\n"
    "sd_plane :: (float3 p, float3 normal, float offset) -> float {\n"
    "    float3 n = Math::safe_normalize(normal);\n"
    "    return dot(p, n) + offset;\n"
    "}\n"
    "\n"
    "/// Analytic normal for a sphere centered at the origin.\n"
    "normal_sphere :: (float3 p) -> float3 {\n"
    "    return Math::safe_normalize(p);\n"
    "}\n"
    "\n"
    "/// Analytic normal for a plane.\n"
    "normal_plane :: (float3 normal) -> float3 {\n"
    "    return Math::safe_normalize(normal);\n"
    "}\n"
    "\n"
    "/// Sum-type wrapper for common SDF primitives.\n"
    "enum SDFShape {\n"
    "    Sphere(float radius),\n"
    "    Box(float3 halfExtents),\n"
    "    RoundBox(float3 halfExtents, float radius),\n"
    "    Torus(float majorRadius, float minorRadius),\n"
    "    Capsule(float3 a, float3 b, float radius),\n"
    "    Cylinder(float radius, float halfHeight),\n"
    "    Plane(float3 normal, float offset),\n"
    "\n"
    "    /// Evaluates signed distance for this shape at point p.\n"
    "    eval distance :: (float3 p) -> float {\n"
    "        Sphere(radius): sd_sphere(p, radius)\n"
    "        Box(halfExtents): sd_box(p, halfExtents)\n"
    "        RoundBox(halfExtents, radius): sd_round_box(p, halfExtents, radius)\n"
    "        Torus(majorRadius, minorRadius): sd_torus(p, majorRadius, minorRadius)\n"
    "        Capsule(a, b, radius): sd_capsule(p, a, b, radius)\n"
    "        Cylinder(radius, halfHeight): sd_cylinder(p, radius, halfHeight)\n"
    "        Plane(normal, offset): sd_plane(p, normal, offset)\n"
    "    }\n"
    "\n"
    "    /// Estimates a normal from central differences.\n"
    "    eval normal :: (float3 p, float eps) -> float3 {\n"
    "        float3 ex = float3(eps, 0.0, 0.0);\n"
    "        float3 ey = float3(0.0, eps, 0.0);\n"
    "        float3 ez = float3(0.0, 0.0, eps);\n"
    "        return Math::safe_normalize(float3(\n"
    "            self.distance(p + ex) - self.distance(p - ex),\n"
    "            self.distance(p + ey) - self.distance(p - ey),\n"
    "            self.distance(p + ez) - self.distance(p - ez)\n"
    "        ));\n"
    "    }\n"
    "}\n"
    "\n"
    "/// Boolean composition operation for combine().\n"
    "enum SDFCombineOp : int {\n"
    "    Union = 0,\n"
    "    Intersection = 1,\n"
    "    Subtract = 2,\n"
    "    SmoothUnion = 3,\n"
    "    SmoothIntersection = 4,\n"
    "    SmoothSubtract = 5\n"
    "}\n"
    "\n"
    "// ============================================\n"
    "// Domain Helpers\n"
    "// ============================================\n"
    "\n"
    "/// Moves the SDF sample point into a translated object's local space.\n"
    "translate :: (float3 p, float3 offset) -> float3 {\n"
    "    return p - offset;\n"
    "}\n"
    "\n"
    "/// Uniformly scales the SDF sample point. Multiply returned distances by scale.\n"
    "scale_uniform :: (float3 p, float scale) -> float3 {\n"
    "    return p / max(scale, Math::EPSILON);\n"
    "}\n"
    "\n"
    "/// Repeats the sample point in a grid of cells with the given spacing.\n"
    "/// Reference: https://iquilezles.org/articles/distfunctions/\n"
    "repeat :: (float3 p, float3 spacing) -> float3 {\n"
    "    float3 s = max(spacing, float3(Math::EPSILON));\n"
    "    return p - s * floor(p / s + float3(0.5));\n"
    "}\n"
    "\n"
    "/// Repeats the sample point on XZ while leaving Y unchanged.\n"
    "repeat_xz :: (float3 p, float2 spacing) -> float3 {\n"
    "    float2 s = max(spacing, float2(Math::EPSILON));\n"
    "    float2 xz = p.xz - s * floor(p.xz / s + float2(0.5));\n"
    "    return float3(xz.x, p.y, xz.y);\n"
    "}\n"
    "\n"
    "// ============================================\n"
    "// Boolean Composition\n"
    "// ============================================\n"
    "\n"
    "/// Union of two signed distances.\n"
    "op_union :: (float a, float b) -> float {\n"
    "    return min(a, b);\n"
    "}\n"
    "\n"
    "/// Intersection of two signed distances.\n"
    "op_intersection :: (float a, float b) -> float {\n"
    "    return max(a, b);\n"
    "}\n"
    "\n"
    "/// Difference of signed distance a minus b.\n"
    "op_subtract :: (float a, float b) -> float {\n"
    "    return max(a, -b);\n"
    "}\n"
    "\n"
    "/// Smooth polynomial union of two signed distances.\n"
    "/// Reference: https://iquilezles.org/articles/smin/\n"
    "smooth_union :: (float a, float b, float k) -> float {\n"
    "    float h = saturate(0.5 + 0.5 * (b - a) / max(k, Math::EPSILON));\n"
    "    return lerp(b, a, h) - k * h * (1.0 - h);\n"
    "}\n"
    "\n"
    "/// Smooth polynomial intersection of two signed distances.\n"
    "/// Reference: https://iquilezles.org/articles/smin/\n"
    "smooth_intersection :: (float a, float b, float k) -> float {\n"
    "    return -smooth_union(-a, -b, k);\n"
    "}\n"
    "\n"
    "/// Smooth polynomial subtraction of signed distance b from a.\n"
    "/// Reference: https://iquilezles.org/articles/smin/\n"
    "smooth_subtract :: (float a, float b, float k) -> float {\n"
    "    return smooth_intersection(a, -b, k);\n"
    "}\n"
    "\n"
    "/// Combines two signed distances using an enum-selected operation.\n"
    "/// Smooth operations use k as the blend radius; hard operations ignore k.\n"
    "combine :: (SDFCombineOp op, float a, float b, float k) -> float {\n"
    "    if (op == SDFCombineOp::Union) {\n"
    "        return op_union(a, b);\n"
    "    }\n"
    "    if (op == SDFCombineOp::Intersection) {\n"
    "        return op_intersection(a, b);\n"
    "    }\n"
    "    if (op == SDFCombineOp::Subtract) {\n"
    "        return op_subtract(a, b);\n"
    "    }\n"
    "    if (op == SDFCombineOp::SmoothUnion) {\n"
    "        return smooth_union(a, b, k);\n"
    "    }\n"
    "    if (op == SDFCombineOp::SmoothIntersection) {\n"
    "        return smooth_intersection(a, b, k);\n"
    "    }\n"
    "    if (op == SDFCombineOp::SmoothSubtract) {\n"
    "        return smooth_subtract(a, b, k);\n"
    "    }\n"
    "    return a;\n"
    "}\n"
    "\n"
    "// ============================================\n"
    "// Shading Helpers\n"
    "// ============================================\n"
    "\n"
    "/// Returns a soft inside/outside mask for distance d.\n"
    "soft_mask :: (float d, float feather) -> float {\n"
    "    return saturate(0.5 - d / max(feather, Math::EPSILON));\n"
    "}\n"
    "\n"
    "/// Returns a contour line mask around multiples of spacing.\n"
    "contour :: (float d, float spacing, float width) -> float {\n"
    "    float s = max(spacing, Math::EPSILON);\n"
    "    float w = max(width, Math::EPSILON);\n"
    "    float line = abs(fract(d / s + 0.5) - 0.5) * s;\n"
    "    return 1.0 - smoothstep(0.0, w, line);\n"
    "}\n"
    "\n"
    "/// Returns a simple surface color blend based on signed distance.\n"
    "distance_color :: (float d, float bandWidth, float3 insideColor, float3 outsideColor) -> float3 {\n"
    "    float t = soft_mask(d, bandWidth);\n"
    "    return lerp(outsideColor, insideColor, t);\n"
    "}\n"
    "\n"
    "// ============================================\n"
    "// Ray Marching\n"
    "// ============================================\n"
    "\n"
    "/// Builds a ray and safely normalizes its direction.\n"
    "make_ray :: (float3 origin, float3 direction) -> Ray {\n"
    "    Ray ray;\n"
    "    ray.origin = origin;\n"
    "    ray.direction = Math::safe_normalize(direction);\n"
    "    return ray;\n"
    "}\n"
    "\n"
    "/// Raymarches one shape.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Ray_marching\n"
    "raymarch_shape :: (SDFShape shape, Ray ray, float minDistance, float maxDistance, float hitEpsilon, int maxSteps) -> RaymarchResult {\n"
    "    RaymarchResult result;\n"
    "    result.hit = false;\n"
    "    result.steps = 0;\n"
    "    result.distance = minDistance;\n"
    "    result.position = ray.origin + ray.direction * minDistance;\n"
    "    result.surfaceDistance = 0.0;\n"
    "\n"
    "    float t = minDistance;\n"
    "    for (int i = 0; i < maxSteps; i++) {\n"
    "        float3 p = ray.origin + ray.direction * t;\n"
    "        float d = shape.distance(p);\n"
    "\n"
    "        result.steps = i + 1;\n"
    "        result.distance = t;\n"
    "        result.position = p;\n"
    "        result.surfaceDistance = d;\n"
    "\n"
    "        if (abs(d) <= hitEpsilon) {\n"
    "            result.hit = true;\n"
    "            return result;\n"
    "        }\n"
    "\n"
    "        t += d;\n"
    "        if (t > maxDistance) {\n"
    "            return result;\n"
    "        }\n"
    "    }\n"
    "\n"
    "    return result;\n"
    "}\n"
    "\n"
    "/// Convenience wrapper for the common single-sphere case.\n"
    "raymarch_sphere :: (float radius, Ray ray, float minDistance, float maxDistance, float hitEpsilon, int maxSteps) -> RaymarchResult {\n"
    "    SDFShape shape = SDFShape::Sphere(radius);\n"
    "    return raymarch_shape(shape, ray, minDistance, maxDistance, hitEpsilon, maxSteps);\n"
    "}\n"
    "\n"
    "}\n"
    ;

static constexpr const char kSpacesSource[] =
    "module Spaces {\n"
    "\n"
    "import Math\n"
    "\n"
    "struct Ray {\n"
    "    float3 origin;\n"
    "    float3 direction;\n"
    "};\n"
    "\n"
    "struct Basis {\n"
    "    float3 tangent;\n"
    "    float3 bitangent;\n"
    "    float3 normal;\n"
    "};\n"
    "\n"
    "/// Transforms a position by a 4x4 matrix and performs perspective divide when w is nonzero.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Homogeneous_coordinates\n"
    "transform_point :: (mat4 m, float3 p) -> float3 {\n"
    "    float4 h = m * float4(p, 1.0);\n"
    "    float3 xyz = float3(h.x, h.y, h.z);\n"
    "    if (abs(h.w) > Math::EPSILON) {\n"
    "        return xyz / h.w;\n"
    "    }\n"
    "    return xyz;\n"
    "}\n"
    "\n"
    "/// Transforms a direction or offset by a 4x4 matrix without translation.\n"
    "transform_vector :: (mat4 m, float3 v) -> float3 {\n"
    "    float4 h = m * float4(v, 0.0);\n"
    "    return float3(h.x, h.y, h.z);\n"
    "}\n"
    "\n"
    "/// Transforms and normalizes a direction or offset by a 4x4 matrix.\n"
    "transform_direction :: (mat4 m, float3 v) -> float3 {\n"
    "    return Math::safe_normalize(transform_vector(m, v));\n"
    "}\n"
    "\n"
    "/// Transforms a normal by the inverse-transpose of an object-to-world matrix.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Normal_(geometry)\n"
    "transform_normal :: (mat4 objectToWorld, float3 n) -> float3 {\n"
    "    mat4 normalMatrix = transpose(inverse(objectToWorld));\n"
    "    float4 h = normalMatrix * float4(n, 0.0);\n"
    "    return Math::safe_normalize(float3(h.x, h.y, h.z));\n"
    "}\n"
    "\n"
    "/// Projects a world-space position to clip space with a view-projection matrix.\n"
    "project_point :: (mat4 viewProjection, float3 worldPos) -> float4 {\n"
    "    return viewProjection * float4(worldPos, 1.0);\n"
    "}\n"
    "\n"
    "/// Converts clip-space coordinates to normalized device coordinates by dividing by w.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Viewing_frustum\n"
    "clip_to_ndc :: (float4 clipPos) -> float3 {\n"
    "    float3 xyz = float3(clipPos.x, clipPos.y, clipPos.z);\n"
    "    if (abs(clipPos.w) > Math::EPSILON) {\n"
    "        return xyz / clipPos.w;\n"
    "    }\n"
    "    return xyz;\n"
    "}\n"
    "\n"
    "/// Converts normalized device coordinates in [-1, 1] to texture UV coordinates in [0, 1].\n"
    "ndc_to_uv :: (float2 ndc) -> float2 {\n"
    "    return ndc * 0.5 + float2(0.5);\n"
    "}\n"
    "\n"
    "/// Converts texture UV coordinates in [0, 1] to normalized device coordinates in [-1, 1].\n"
    "uv_to_ndc :: (float2 uv) -> float2 {\n"
    "    return uv * 2.0 - float2(1.0);\n"
    "}\n"
    "\n"
    "/// Converts pixel coordinates to normalized UV coordinates using viewport size.\n"
    "screen_to_uv :: (float2 pixel, float2 viewportSize) -> float2 {\n"
    "    return pixel / max(viewportSize, float2(1.0));\n"
    "}\n"
    "\n"
    "/// Converts normalized UV coordinates to pixel coordinates using viewport size.\n"
    "uv_to_screen :: (float2 uv, float2 viewportSize) -> float2 {\n"
    "    return uv * viewportSize;\n"
    "}\n"
    "\n"
    "/// Linearizes a hardware depth value in [0, 1] to normalized view depth.\n"
    "/// Reference: https://developer.nvidia.com/content/depth-precision-visualized\n"
    "linearize_depth_01 :: (float depth, float nearPlane, float farPlane) -> float {\n"
    "    return (2.0 * nearPlane) / (farPlane + nearPlane - depth * (farPlane - nearPlane));\n"
    "}\n"
    "\n"
    "/// Linearizes an NDC depth value in [-1, 1] to view-space depth units.\n"
    "linearize_depth_ndc :: (float ndcDepth, float nearPlane, float farPlane) -> float {\n"
    "    return (2.0 * nearPlane * farPlane) / (farPlane + nearPlane - ndcDepth * (farPlane - nearPlane));\n"
    "}\n"
    "\n"
    "/// Reconstructs view-space position from UV, depth, and inverse projection.\n"
    "/// Reference: https://mynameismjp.wordpress.com/2009/03/10/reconstructing-position-from-depth/\n"
    "reconstruct_view_position :: (float2 uv, float depth, mat4 inverseProjection) -> float3 {\n"
    "    float4 clip = float4(uv_to_ndc(uv), depth * 2.0 - 1.0, 1.0);\n"
    "    float4 view = inverseProjection * clip;\n"
    "    float3 xyz = float3(view.x, view.y, view.z);\n"
    "    if (abs(view.w) > Math::EPSILON) {\n"
    "        return xyz / view.w;\n"
    "    }\n"
    "    return xyz;\n"
    "}\n"
    "\n"
    "/// Reconstructs world-space position from UV, depth, and inverse view-projection.\n"
    "/// Reference: https://mynameismjp.wordpress.com/2009/03/10/reconstructing-position-from-depth/\n"
    "reconstruct_world_position :: (float2 uv, float depth, mat4 inverseViewProjection) -> float3 {\n"
    "    float4 clip = float4(uv_to_ndc(uv), depth * 2.0 - 1.0, 1.0);\n"
    "    float4 world = inverseViewProjection * clip;\n"
    "    float3 xyz = float3(world.x, world.y, world.z);\n"
    "    if (abs(world.w) > Math::EPSILON) {\n"
    "        return xyz / world.w;\n"
    "    }\n"
    "    return xyz;\n"
    "}\n"
    "\n"
    "/// Builds an orthonormal tangent basis around a normal.\n"
    "/// Reference: https://en.wikipedia.org/wiki/Orthonormal_basis\n"
    "make_basis :: (float3 normal) -> Basis {\n"
    "    float3 n = Math::safe_normalize(normal);\n"
    "    float3 up = abs(n.z) < 0.999 ? float3(0.0, 0.0, 1.0) : float3(1.0, 0.0, 0.0);\n"
    "    float3 tangent = Math::safe_normalize(cross(up, n));\n"
    "\n"
    "    Basis basis;\n"
    "    basis.tangent = tangent;\n"
    "    basis.bitangent = cross(n, tangent);\n"
    "    basis.normal = n;\n"
    "    return basis;\n"
    "}\n"
    "\n"
    "/// Converts a tangent-space vector to world space using a Basis.\n"
    "tangent_to_world :: (float3 tangentSpaceVector, Basis basis) -> float3 {\n"
    "    return basis.tangent * tangentSpaceVector.x +\n"
    "           basis.bitangent * tangentSpaceVector.y +\n"
    "           basis.normal * tangentSpaceVector.z;\n"
    "}\n"
    "\n"
    "/// Converts a tangent-space vector to world space from explicit tangent, bitangent, and normal.\n"
    "tangent_to_world :: (float3 tangentSpaceVector, float3 tangent, float3 bitangent, float3 normal) -> float3 {\n"
    "    return tangent * tangentSpaceVector.x +\n"
    "           bitangent * tangentSpaceVector.y +\n"
    "           normal * tangentSpaceVector.z;\n"
    "}\n"
    "\n"
    "/// Converts a world-space vector into tangent space using a Basis.\n"
    "world_to_tangent :: (float3 worldVector, Basis basis) -> float3 {\n"
    "    return float3(\n"
    "        dot(worldVector, basis.tangent),\n"
    "        dot(worldVector, basis.bitangent),\n"
    "        dot(worldVector, basis.normal)\n"
    "    );\n"
    "}\n"
    "\n"
    "/// Builds a view-space ray through a screen UV from an inverse projection matrix.\n"
    "view_ray_from_uv :: (float2 uv, mat4 inverseProjection) -> Ray {\n"
    "    float3 nearPos = reconstruct_view_position(uv, 0.0, inverseProjection);\n"
    "    float3 farPos = reconstruct_view_position(uv, 1.0, inverseProjection);\n"
    "\n"
    "    Ray ray;\n"
    "    ray.origin = nearPos;\n"
    "    ray.direction = Math::safe_normalize(farPos - nearPos);\n"
    "    return ray;\n"
    "}\n"
    "\n"
    "}\n"
    ;

