static constexpr u32 kModuleCount = static_cast<u32>(sizeof(kModules) / sizeof(kModules[0]));

inline const ModuleSource* FindByHash(u32 nameHash) {
    for (u32 i = 0; i < kModuleCount; i++) {
        if (kModules[i].nameHash == nameHash) {
            return &kModules[i];
        }
    }
    return nullptr;
}

